815→/** Get simple project context for plugin tools. Returns undefined if project not found or outside workspace. */
816→export async function getPluginProjectContext(input: {
817→  surreal: Surreal;
818→  workspaceRecord: RecordId<"workspace", string>;
819→  projectRecord: RecordId<"project", string>;
820→}): Promise<PluginProjectContext | undefined> {
821→  const project = await input.surreal.select<PluginProjectRow>(input.projectRecord);
822→  if (!project) return undefined;
823→  if ((project.workspace?.id as string) !== (input.workspaceRecord.id as string)) return undefined;
