825→  // Count tasks and features belonging to this project
826→  const [countResults] = await input.surreal
827→    .query<[Array<{ task_count: number; feature_count: number }>]>(
828→      `SELECT
829→         (SELECT count() FROM task WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL)[0].count AS task_count,
830→         (SELECT count() FROM feature WHERE id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project) GROUP ALL)[0].count AS feature_count;`,
831→      { project: input.projectRecord },
832→    )
833→    .collect<[Array<{ task_count: number; feature_count: number }>]>();
834→
835→  const counts = countResults[0];
836→
837→  return {
838→    name: project.name,
839→    status: project.status,
840→    ...(project.description ? { description: project.description } : {}),
841→    taskCount: counts?.task_count ?? 0,
842→    featureCount: counts?.feature_count ?? 0,
843→  };
844→}
