846→// ---------------------------------------------------------------------------
847→// Utility
848→// ---------------------------------------------------------------------------
849→
850→function levenshteinSimilarity(a: string, b: string): number {
851→  if (a === b) return 1;
852→  const longer = a.length > b.length ? a : b;
853→  const shorter = a.length > b.length ? b : a;
854→  if (longer.length === 0) return 1;
855→
856→  const costs: number[] = [];
857→  for (let i = 0; i <= longer.length; i++) {
858→    let lastValue = i;
859→    for (let j = 0; j <= shorter.length; j++) {
860→      if (i === 0) {
861→        costs[j] = j;
862→      } else if (j > 0) {
863→        let newValue = costs[j - 1];
864→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
865→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
866→        }
867→        costs[j - 1] = lastValue;
868→        lastValue = newValue;
869→      }
870→    }
871→    if (i > 0) costs[shorter.length] = lastValue;
872→  }
873→
874→  return (longer.length - costs[shorter.length]) / longer.length;
875→}
