537→export async function acceptOrchestratorSession(
538→  input: AcceptSessionInput,
539→): Promise<AcceptSessionResult> {
540→  const lookup = await lookupSession(input.surreal, input.sessionId);
541→  if (!lookup.ok) {
542→    return { ok: false, error: lookup.error };
543→  }
544→  const { session, record: sessionRecord, status } = lookup;
545→
546→  if (!ACCEPTABLE_STATUSES.has(status)) {
547→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
548→  }
549→
550→  const workspaceRecord = requireWorkspace(session, input.sessionId);
551→
552→  // 1. Update orchestrator_status to completed
553→  await input.surreal.update(sessionRecord).merge({
554→    orchestrator_status: "completed" as OrchestratorStatus,
555→  });
556→
557→  // 2. Clean up handle registry
558→  handleRegistry.delete(input.sessionId);
559→
560→  // 4. End the agent session
561→  await input.endAgentSession({
562→    surreal: input.surreal,
563→    workspaceRecord,
564→    sessionId: input.sessionId,
565→    summary: input.summary,
566→  });
567→
568→  return {
569→    ok: true,
570→    value: {
571→      accepted: true,
572→      sessionId: input.sessionId,
573→    },
574→  };
575→}
