577→// ---------------------------------------------------------------------------
578→// State guard helpers
579→// ---------------------------------------------------------------------------
580→
581→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
582→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
583→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
584→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
585→
586→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
587→  return {
588→    code: "SESSION_ERROR",
589→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
590→    httpStatus: 409,
591→  };
592→}
593→
594→function sessionAborted(sessionId: string): SessionError {
595→  return {
596→    code: "SESSION_ERROR",
597→    message: `Session ${sessionId} has been aborted`,
598→    httpStatus: 409,
599→  };
600→}
