711→
712→type SendPromptInput = {
713→  surreal: Surreal;
714→  sessionId: string;
715→  text: string;
716→};
717→
718→export async function sendSessionPrompt(
719→  input: SendPromptInput,
720→): Promise<PromptSessionResult> {
721→  const lookup = await lookupSession(input.surreal, input.sessionId);
722→  if (!lookup.ok) {
723→    return { ok: false, error: lookup.error };
724→  }
725→  const { status } = lookup;
726→
727→  if (!PROMPTABLE_STATUSES.has(status)) {
728→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
729→  }
730→
731→  // The Claude Agent SDK uses a single query() call per conversation.
732→  // Follow-up prompts are not supported in this model.
733→  return {
734→    ok: false,
735→    error: {
736→      code: "SESSION_ERROR",
737→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
738→      httpStatus: 409,
739→    },
740→  };
741→}
