 53→// ---------------------------------------------------------------------------
 54→// Step 1: Auth (OAuth 2.1 PKCE)
 55→// ---------------------------------------------------------------------------
 56→
 57→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
 58→
 59→function base64url(buf: Buffer): string {
 60→  return buf.toString("base64url");
 61→}
 62→
 63→function generatePkce(): { verifier: string; challenge: string } {
 64→  const verifier = base64url(randomBytes(32));
 65→  const challenge = base64url(createHash("sha256").update(verifier).digest());
 66→  return { verifier, challenge };
 67→}
 68→
 69→export async function setupAuth(
 70→  serverUrl: string,
 71→  workspaceId: string,
 72→  gitRoot: string,
 73→  options?: { openUrl?: (url: string) => void },
 74→): Promise<void> {
 75→  const global = await loadGlobalConfig();
 76→  const existing = global?.repos[gitRoot];
 77→  if (existing && existing.workspace === workspaceId && existing.access_token) {
 78→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 79→    return;
 80→  }
 81→
 82→  // 1. Verify workspace exists
 83→  try {
 84→    await BrainHttpClient.listProjects(serverUrl, workspaceId);
 85→  } catch {
 86→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
 87→    process.exit(1);
 88→  }
 89→
 90→  // 2. Dynamic Client Registration
 91→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
 92→    method: "POST",
 93→    headers: { "Content-Type": "application/json" },
 94→    body: JSON.stringify({
 95→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
 96→      redirect_uris: ["http://127.0.0.1/callback"],
 97→      grant_types: ["authorization_code", "refresh_token"],
 98→      response_types: ["code"],
 99→      token_endpoint_auth_method: "none",
100→    }),
101→  });
102→  if (!dcrRes.ok) {
103→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
104→  }
105→  const { client_id } = await dcrRes.json() as { client_id: string };
106→
107→  // 3. PKCE
108→  const pkce = generatePkce();
109→  const state = base64url(randomBytes(16));
110→
111→  // 4. Start local callback server
112→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
113→
114→  const callbackServer = Bun.serve({
115→    port: 0,
116→    hostname: "127.0.0.1",
117→    routes: {
118→      "/callback": (request) => {
119→        const url = new URL(request.url);
120→        const code = url.searchParams.get("code");
121→        const returnedState = url.searchParams.get("state");
122→        const error = url.searchParams.get("error");
123→
124→        if (error) {
125→          rejectCode(new Error(`OAuth error: ${error}`));
126→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
127→            headers: { "Content-Type": "text/html" },
128→          });
129→        }
130→        if (returnedState !== state) {
131→          rejectCode(new Error("state mismatch"));
132→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
133→            headers: { "Content-Type": "text/html" },
134→          });
135→        }
136→        if (!code) {
137→          rejectCode(new Error("no code returned"));
138→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
139→            headers: { "Content-Type": "text/html" },
140→          });
141→        }
142→
143→        resolveCode(code);
144→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
145→          headers: { "Content-Type": "text/html" },
146→        });
147→      },
148→    },
149→  });
150→
151→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
152→
153→  // Update redirect_uris with actual port (re-register)
154→  const dcrUpdateRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
155→    method: "POST",
156→    headers: { "Content-Type": "application/json" },
157→    body: JSON.stringify({
158→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
159→      redirect_uris: [redirectUri],
160→      grant_types: ["authorization_code", "refresh_token"],
161→      response_types: ["code"],
162→      token_endpoint_auth_method: "none",
163→    }),
164→  });
165→  if (!dcrUpdateRes.ok) {
166→    callbackServer.stop();
167→    throw new Error(`Client re-registration failed: ${dcrUpdateRes.status} ${await dcrUpdateRes.text()}`);
168→  }
169→  const dcrUpdate = await dcrUpdateRes.json() as { client_id: string };
170→  const actualClientId = dcrUpdate.client_id;
171→
172→  // 5. Open browser
173→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
174→  authUrl.searchParams.set("client_id", actualClientId);
175→  authUrl.searchParams.set("redirect_uri", redirectUri);
176→  authUrl.searchParams.set("response_type", "code");
177→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
178→  authUrl.searchParams.set("code_challenge", pkce.challenge);
179→  authUrl.searchParams.set("code_challenge_method", "S256");
180→  authUrl.searchParams.set("state", state);
181→  // Pass resource so better-auth issues a JWT access token (not opaque)
182→  authUrl.searchParams.set("resource", `${serverUrl}/api/auth`);
183→
184→  console.log("Opening browser for authentication...");
185→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
186→
187→  const openUrl = options?.openUrl ?? ((url: string) => {
188→    const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
189→    Bun.spawn([openCmd, url], { stdout: "ignore", stderr: "ignore" });
190→  });
191→  openUrl(authUrl.toString());
192→
193→  // 6. Wait for callback
194→  let code: string;
195→  try {
196→    code = await codePromise;
197→  } catch (error) {
198→    callbackServer.stop();
199→    throw error;
200→  }
201→
202→  // 7. Exchange code for tokens
203→  const tokenRes = await fetch(`${serverUrl}/api/auth/oauth2/token`, {
204→    method: "POST",
205→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
206→    body: new URLSearchParams({
207→      grant_type: "authorization_code",
208→      code,
209→      redirect_uri: redirectUri,
210→      client_id: actualClientId,
211→      code_verifier: pkce.verifier,
212→      resource: `${serverUrl}/api/auth`,
213→    }),
214→  });
215→
216→  callbackServer.stop();
217→
218→  if (!tokenRes.ok) {
219→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
220→  }
221→
222→  const tokens = await tokenRes.json() as {
223→    access_token: string;
224→    refresh_token: string;
225→    expires_in: number;
226→    token_type: string;
227→  };
228→
229→  // 8. Store tokens
230→  await saveRepoConfig(serverUrl, gitRoot, {
231→    workspace: workspaceId,
232→    client_id: actualClientId,
233→    access_token: tokens.access_token,
234→    refresh_token: tokens.refresh_token,
235→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
236→  });
237→
238→  console.log(`✓ Auth: OAuth tokens saved for ${gitRoot}`);
239→}
