267→
268→type HookEntry = { type: string; command?: string; prompt?: string };
269→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
270→
271→export async function setupClaudeHooks(gitRoot: string): Promise<void> {
272→  const claudeDir = join(gitRoot, ".claude");
273→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
274→
275→  const settingsPath = join(claudeDir, "settings.json");
276→  const file = Bun.file(settingsPath);
277→  let settings: Record<string, unknown> = {};
278→
279→  if (await file.exists()) {
280→    try {
281→      settings = await file.json();
282→    } catch {
283→      // Corrupted — start fresh
284→    }
285→  }
286→
287→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
288→  let added = 0;
289→
290→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
291→    hooks[event] ??= [];
292→
293→    const hasBrain = hooks[event].some((group) =>
294→      group.hooks?.some(
295→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
296→      ),
297→    );
298→
299→    if (!hasBrain) {
300→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
301→      added++;
302→    }
303→  }
304→
305→  settings.hooks = hooks;
306→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
307→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
308→}
