317→export async function setupClaudeMd(gitRoot: string): Promise<void> {
318→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
319→  const file = Bun.file(claudeMdPath);
320→  let content = "";
321→
322→  if (await file.exists()) {
323→    content = await file.text();
324→  }
325→
326→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
327→
328→  const startIdx = content.indexOf(MARKER_START);
329→  const endIdx = content.indexOf(MARKER_END);
330→
331→  if (startIdx !== -1 && endIdx !== -1) {
332→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
333→  } else {
334→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
335→    content = content + separator + brainBlock + "\n";
336→  }
337→
338→  await Bun.write(claudeMdPath, content);
339→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
340→}
