345→
346→export function installGitHooks(gitRoot?: string): void {
347→  const root = gitRoot ?? findGitRoot(process.cwd());
348→  if (!root) {
349→    console.log("  No .git directory found — skipping git hook installation.");
350→    return;
351→  }
352→
353→  const hooksDir = join(root, ".git", "hooks");
354→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
355→
356→  const preCommitPath = join(hooksDir, "pre-commit");
357→  const postCommitPath = join(hooksDir, "post-commit");
358→  const preCommitScript = `#!/bin/sh
359→# Brain pre-commit hook: check for task completion and unlogged decisions
360→brain check-commit
361→`;
362→
363→  if (!existsSync(preCommitPath)) {
364→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
365→    console.log("✓ Git: pre-commit hook installed");
366→  } else {
367→    console.log("✓ Git: pre-commit hook already exists");
368→  }
369→
370→  // Remove legacy Brain post-commit hook
371→  if (existsSync(postCommitPath)) {
372→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
373→    const isBrainManaged =
374→      postCommitContent.includes("Brain post-commit hook") &&
375→      postCommitContent.includes("brain log-commit");
376→    if (isBrainManaged) {
377→      unlinkSync(postCommitPath);
378→      console.log("  Removed legacy Brain post-commit hook");
379→    }
380→  }
381→}
