 28→// --- Commit Processing ---
 29→
 30→export type CommitInput = {
 31→  sha: string;
 32→  message: string;
 33→  authoredAt: string;
 34→  authorName: string;
 35→  authorEmail: string;
 36→  authorUsername?: string;
 37→  url: string;
 38→  repository: string;
 39→};
 40→
 41→export type ProcessCommitInput = {
 42→  surreal: Surreal;
 43→  extractionModel: unknown;
 44→  embeddingModel: unknown;
 45→  embeddingDimension: number;
 46→  extractionStoreThreshold: number;
 47→  extractionModelId: string;
 48→  workspaceRecord: RecordId<"workspace", string>;
 49→  commit: CommitInput;
 50→  workspaceName?: string;
 51→  projectNames?: string[];
 52→  autoLinkThreshold: number;
 53→  now: Date;
 54→};
 55→
 56→export type ProcessCommitResult = {
 57→  commitRecord: RecordId<"git_commit", string>;
 58→  entities: ExtractedEntity[];
 59→  relationships: ExtractedRelationship[];
 60→  autoLinkedDecisions: string[];
 61→  observationsCreated: string[];
 62→};
 63→
 64→// --- Webhook Processing ---
 65→
 66→export type ProcessWebhookInput = {
 67→  surreal: Surreal;
 68→  extractionModel: unknown;
 69→  embeddingModel: unknown;
 70→  embeddingDimension: number;
 71→  extractionStoreThreshold: number;
 72→  extractionModelId: string;
 73→  workspaceRecord: RecordId<"workspace", string>;
 74→  event: GitHubPushEvent;
 75→  autoLinkThreshold: number;
 76→};
 77→
 78→export type ProcessWebhookResult = {
 79→  commitsProcessed: number;
 80→  commitsSkipped: number;
 81→  totalEntities: number;
 82→  totalRelationships: number;
 83→  autoLinkedDecisions: string[];
 84→  observationsCreated: string[];
 85→};
 86→
 87→// --- Decision Linking Classification ---
 88→
 89→export type DecisionLinkAction =
 90→  | { action: "auto_link"; entityId: string; confidence: number }
 91→  | { action: "observe"; entityId: string; text: string; confidence: number };
 92→
 93→export function classifyDecisionLinks(
 94→  entities: Array<{ id: string; kind: EntityKind; text: string; confidence: number }>,
 95→  autoLinkThreshold: number,
 96→): DecisionLinkAction[] {
 97→  const actions: DecisionLinkAction[] = [];
 98→  for (const entity of entities) {
 99→    if (entity.kind !== "decision") continue;
100→    if (entity.confidence >= autoLinkThreshold) {
101→      actions.push({ action: "auto_link", entityId: entity.id, confidence: entity.confidence });
102→    } else {
103→      actions.push({ action: "observe", entityId: entity.id, text: entity.text, confidence: entity.confidence });
104→    }
105→  }
106→  return actions;
107→}
