  5→/**
  6→ * US-3: brain commit-check parses task refs and sets tasks to done.
  7→ *
  8→ * Tests the server endpoint POST /api/mcp/:workspaceId/commits/check
  9→ * which accepts a commit message, extracts task refs (regex fast path),
 10→ * and sets matched tasks to done.
 11→ */
 12→
 13→const getRuntime = setupSmokeSuite("commit-check");
 14→
 15→async function setupWorkspaceWithTasks(
 16→  baseUrl: string,
 17→  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
 18→  suffix: string,
 19→  tasks: Array<{ id: string; title: string; status: string }>,
 20→) {
 21→  const user = await createTestUser(baseUrl, `commit-check-${suffix}`);
 22→
 23→  const workspace = await fetchJson<{ workspaceId: string }>(
 24→    `${baseUrl}/api/workspaces`,
 25→    {
 26→      method: "POST",
 27→      headers: { "Content-Type": "application/json", ...user.headers },
 28→      body: JSON.stringify({ name: `Commit Check ${Date.now()} ${suffix}` }),
 29→    },
 30→  );
 31→
 32→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
 33→  const taskRecords: Array<{ id: string; record: RecordId<"task", string> }> = [];
 34→
 35→  for (const task of tasks) {
 36→    const taskRecord = new RecordId("task", task.id);
 37→    await surreal.create(taskRecord).content({
 38→      workspace: workspaceRecord,
 39→      title: task.title,
 40→      status: task.status,
 41→      category: "backend",
 42→      priority: "medium",
 43→      created_at: new Date(),
 44→      updated_at: new Date(),
 45→    });
 46→    taskRecords.push({ id: task.id, record: taskRecord });
 47→  }
 48→
 49→  return { user, workspace, workspaceRecord, taskRecords };
 50→}
