288→
289→  const query = `
290→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
291→    FROM decision
292→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
293→    ORDER BY updated_at DESC LIMIT 20;
294→
295→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
296→    FROM task
297→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
298→    ORDER BY updated_at DESC LIMIT 20;
299→
300→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
301→    FROM question
302→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
303→    ORDER BY updated_at DESC LIMIT 20;
304→
305→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
306→  `;
307→
308→  const results = await input.surreal
309→    .query<[null, null, null, EntityChangeRow[]]>(query, {
310→      workspace: input.workspaceRecord,
311→      since: sinceDate,
312→      ...(input.projectRecord ? { project: input.projectRecord } : {}),
313→    })
314→    .collect<[null, null, null, EntityChangeRow[]]>();
315→
316→  return (results[3] ?? []).map((r) => ({
317→    entity_type: r.entity_type,
318→    entity_name: r.entity_name,
319→    change_type: r.change_type,
320→    changed_at: toIso(r.changed_at),
321→  }));
322→}
