458→/** Compute and apply subtask rollup on a parent task */
459→async function computeSubtaskRollup(
460→  surreal: Surreal,
461→  parentRecord: RecordId<"task", string>,
462→): Promise<string> {
463→  const [subtaskRows] = await surreal
464→    .query<[SubtaskRow[]]>(
465→      `SELECT id, title, status
466→       FROM task
467→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
468→      { parent: parentRecord },
469→    )
470→    .collect<[SubtaskRow[]]>();
471→
472→  if (subtaskRows.length === 0) return "unknown";
473→
474→  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
475→  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
476→  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
477→  const allTodo = subtaskRows.every((s) => s.status === "todo");
478→
479→  let derivedStatus: string;
480→
481→  if (allCompleted) derivedStatus = "completed";
482→  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
483→  else if (anyBlocked) derivedStatus = "blocked";
484→  else if (anyInProgress) derivedStatus = "in_progress";
485→  else if (allTodo) derivedStatus = "todo";
486→  else derivedStatus = "in_progress";
487→
488→  await surreal.update(parentRecord).merge({
489→    status: derivedStatus,
490→    updated_at: new Date(),
491→  });
492→
493→  return derivedStatus;
494→}
