564→/** End an agent session with summary */
565→export async function endAgentSession(input: {
566→  surreal: Surreal;
567→  workspaceRecord: RecordId<"workspace", string>;
568→  sessionId: string;
569→  summary: string;
570→  decisionsMade?: string[];
571→  questionsAsked?: string[];
572→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
573→  filesChanged?: Array<{ path: string; change_type: string }>;
574→  observationsLogged?: string[];
575→}): Promise<{ session_id: string; ended: boolean }> {
576→  const now = new Date();
577→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
578→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string>; ended_at?: Date; summary?: string }>(sessionRecord);
579→  if (!session) {
580→    throw new Error(`session not found: ${input.sessionId}`);
581→  }
582→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
583→    throw new Error("session is outside the current workspace scope");
584→  }
585→
586→  // Idempotent: if session already ended, return without overwriting
587→  if (session.ended_at) {
588→    return { session_id: toRawId(sessionRecord), ended: true };
589→  }
590→
591→  await input.surreal.update(sessionRecord).merge({
592→    ended_at: now,
593→    summary: input.summary,
594→    ...(input.decisionsMade?.length
595→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
596→      : {}),
597→    ...(input.questionsAsked?.length
598→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
599→      : {}),
600→    ...(input.tasksProgressed?.length
601→      ? {
602→          tasks_progressed: input.tasksProgressed.map((t) => ({
603→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
604→            from_status: t.from_status,
605→            to_status: t.to_status,
606→          })),
607→        }
608→      : {}),
609→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
610→    ...(input.observationsLogged?.length
611→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
612→      : {}),
613→  });
614→
615→  // Create session -> entity edges
616→  if (input.decisionsMade?.length) {
617→    for (const decisionId of input.decisionsMade) {
618→      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
619→      await input.surreal
620→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
621→          added_at: now,
622→        })
623→        .output("after");
624→    }
625→  }
626→
627→  if (input.questionsAsked?.length) {
628→    for (const questionId of input.questionsAsked) {
629→      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
630→      await input.surreal
631→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
632→          added_at: now,
633→        })
634→        .output("after");
635→    }
636→  }
637→
638→  if (input.tasksProgressed?.length) {
639→    for (const t of input.tasksProgressed) {
640→      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
641→      await input.surreal
642→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
643→          from_status: t.from_status,
644→          to_status: t.to_status,
645→          added_at: now,
646→        })
647→        .output("after");
648→    }
649→  }
650→
651→  return { session_id: toRawId(sessionRecord), ended: true };
652→}
