123→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
124→  TERMINAL_ORCHESTRATOR_STATUSES,
125→);
126→
127→/**
128→ * Iterates the SDK message stream, forwarding messages through the event
129→ * bridge. Transitions session to "active" on first message, starts stall
130→ * detection, and stops on terminal status or error.
131→ *
132→ * Returns a Promise that resolves when iteration ends (for testing).
133→ * In production, this is launched fire-and-forget.
134→ */
135→export function startEventIteration(
136→  deps: EventIterationDeps,
137→  messageStream: AsyncIterable<unknown>,
138→  streamId: string,
139→  sessionId: string,
140→): Promise<void> {
141→  const stallDetector = deps.startStallDetector(sessionId, streamId);
142→
143→  const bridge = startEventBridge(
144→    {
145→      emitEvent: deps.emitEvent,
146→      updateLastEventAt: deps.updateLastEventAt,
147→    },
148→    streamId,
149→    sessionId,
150→    stallDetector,
151→  );
152→
153→  let firstMessageReceived = false;
154→  let messageCount = 0;
155→
156→  async function iterate(): Promise<void> {
157→    logInfo("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
158→    try {
159→      for await (const rawMessage of messageStream) {
160→        messageCount++;
161→        const msg = rawMessage as SdkMessage;
162→        logInfo("orchestrator.iteration", `SDK message received (#${messageCount})`, {
163→          sessionId,
164→          messageType: msg.type,
165→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
166→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
167→        });
168→
169→        // Check if session has reached terminal status
170→        const currentStatus = await deps.getSessionStatus(sessionId);
171→        if (TERMINAL_STATUSES.has(currentStatus)) {
172→          logInfo("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
173→          break;
174→        }
175→
176→        // Transition to active on first message
177→        if (!firstMessageReceived) {
178→          firstMessageReceived = true;
179→          await deps.updateSessionStatus(sessionId, "active");
180→        }
181→
182→        // Forward through event bridge (transform + emit + stall detection)
183→        bridge.handleMessage(msg);
184→      }
185→      logInfo("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
186→    } catch (err) {
187→      const errorMessage = err instanceof Error ? err.message : String(err);
188→      logError("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
189→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
190→    } finally {
191→      if (!firstMessageReceived) {
192→        logWarn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
193→      }
194→      bridge.stop();
195→      handleRegistry.delete(sessionId);
196→    }
197→  }
198→
199→  return iterate();
200→}
