295→// ---------------------------------------------------------------------------
296→// createOrchestratorSession
297→// ---------------------------------------------------------------------------
298→
299→type CreateSessionInput = {
300→  surreal: Surreal;
301→  shellExec: ShellExec;
302→  brainBaseUrl: string;
303→  workspaceId: string;
304→  taskId: string;
305→  spawnAgent?: SpawnAgentFn;
306→  validateAssignment: (
307→    surreal: Surreal,
308→    workspaceId: string,
309→    taskId: string,
310→  ) => Promise<AssignmentResult>;
311→  createAgentSession: (input: {
312→    surreal: Surreal;
313→    agent: string;
314→    workspaceRecord: RecordId<"workspace", string>;
315→    taskId?: string;
316→  }) => Promise<{ session_id: string }>;
317→};
318→
319→export async function createOrchestratorSession(
320→  input: CreateSessionInput,
321→): Promise<OrchestratorSessionResult> {
322→  // 1. Validate assignment eligibility
323→  const assignmentResult = await input.validateAssignment(
324→    input.surreal,
325→    input.workspaceId,
326→    input.taskId,
327→  );
328→
329→  if (!assignmentResult.ok) {
330→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
331→  }
332→
333→  const { validation } = assignmentResult;
334→  const taskSlug = slugFromTitle(validation.title);
335→  const repoRoot = validation.repoPath;
336→
337→  // 2. Create worktree
338→  const worktreeResult = await createWorktree(
339→    input.shellExec,
340→    repoRoot,
341→    taskSlug,
342→  );
343→
344→  if (!worktreeResult.ok) {
345→    return {
346→      ok: false,
347→      error: worktreeError(worktreeResult.error.message),
348→    };
349→  }
350→
351→  const { branchName, worktreePath } = worktreeResult.value;
352→
353→  // 3. Create agent_session record
354→  const { session_id: agentSessionId } = await input.createAgentSession({
355→    surreal: input.surreal,
356→    agent: "claude-agent-sdk",
357→    workspaceRecord: validation.workspaceRecord,
358→    taskId: input.taskId,
359→  });
360→
361→  const streamId = generateStreamId(agentSessionId);
362→
363→  // 4. Build config and spawn agent
364→  const agentSpawnConfig: AgentSpawnConfig = {
365→    prompt: `/brain-start-task ${input.taskId}`,
366→    workDir: worktreePath,
367→    workspaceId: input.workspaceId,
368→    brainBaseUrl: input.brainBaseUrl,
369→  };
370→
371→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
372→  let handle: AgentHandle;
373→  try {
374→    handle = spawnFn(agentSpawnConfig);
375→  } catch (err) {
376→    // Rollback: remove worktree and delete agent_session on spawn failure
377→    await removeWorktree(input.shellExec, repoRoot, branchName);
378→    const sessionRecord = new RecordId("agent_session", agentSessionId);
379→    await input.surreal.delete(sessionRecord);
380→    return {
381→      ok: false,
382→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
383→    };
384→  }
385→
386→  // 5. Register handle for later abort
387→  handleRegistry.set(agentSessionId, handle);
388→
389→  // 6. Update agent_session with orchestrator fields
390→  const sessionRecord = new RecordId("agent_session", agentSessionId);
391→  await input.surreal.update(sessionRecord).merge({
392→    orchestrator_status: "spawning" as OrchestratorStatus,
393→    worktree_branch: branchName,
394→    worktree_path: worktreePath,
395→    stream_id: streamId,
396→  });
397→
398→  return {
399→    ok: true,
400→    value: {
401→      agentSessionId,
402→      streamId,
403→      worktreeBranch: branchName,
404→    },
405→  };
406→}
407→
408→// Default spawn -- placeholder for production use
409→function defaultSpawnAgent(
410→  _config: AgentSpawnConfig,
411→): AgentHandle {
412→  throw new Error(
413→    "spawnAgent not provided -- must be injected for production use",
414→  );
415→}
