454→type AbortSessionInput = {
455→  surreal: Surreal;
456→  shellExec: ShellExec;
457→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
458→  sessionId: string;
459→  endAgentSession: (input: {
460→    surreal: Surreal;
461→    workspaceRecord: RecordId<"workspace", string>;
462→    sessionId: string;
463→    summary: string;
464→  }) => Promise<{ session_id: string; ended: boolean }>;
465→};
466→
467→export async function abortOrchestratorSession(
468→  input: AbortSessionInput,
469→): Promise<AbortSessionResult> {
470→  const lookup = await lookupSession(input.surreal, input.sessionId);
471→  if (!lookup.ok) {
472→    return { ok: false, error: lookup.error };
473→  }
474→  const { session, record: sessionRecord } = lookup;
475→
476→  // 1. Abort the agent process if handle exists
477→  const handle = handleRegistry.get(input.sessionId);
478→  if (handle) {
479→    handle.abort();
480→    handleRegistry.delete(input.sessionId);
481→  }
482→
483→  // 2. Update orchestrator_status to aborted
484→  await input.surreal.update(sessionRecord).merge({
485→    orchestrator_status: "aborted" as OrchestratorStatus,
486→  });
487→
488→  const workspaceRecord = requireWorkspace(session, input.sessionId);
489→
490→  // 3. Remove worktree if branch name exists
491→  if (session.worktree_branch) {
492→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
493→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
494→  }
495→
496→  // 4. Return task to ready
497→  if (session.task_id) {
498→    await input.surreal.update(session.task_id).merge({
499→      status: "ready",
500→      updated_at: new Date(),
501→    });
502→  }
503→
504→  // 5. End the agent session
505→  await input.endAgentSession({
506→    surreal: input.surreal,
507→    workspaceRecord,
508→    sessionId: input.sessionId,
509→    summary: "Session aborted",
510→  });
511→
512→  return {
513→    ok: true,
514→    value: {
515→      aborted: true,
516→      sessionId: input.sessionId,
517→    },
518→  };
519→}
