606→type GetReviewInput = {
607→  surreal: Surreal;
608→  sessionId: string;
609→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
610→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
611→  getTaskTitle: (taskId: string) => Promise<string>;
612→};
613→
614→export async function getOrchestratorReview(
615→  input: GetReviewInput,
616→): Promise<ReviewResult> {
617→  const lookup = await lookupSession(input.surreal, input.sessionId);
618→  if (!lookup.ok) {
619→    return { ok: false, error: lookup.error };
620→  }
621→  const { session, status } = lookup;
622→
623→  if (status === "aborted") {
624→    return { ok: false, error: sessionAborted(input.sessionId) };
625→  }
626→
627→  if (!REVIEWABLE_STATUSES.has(status)) {
628→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
629→  }
630→
631→  // Get diff from the branch
632→  const branchName = session.worktree_branch ?? "";
633→  const workspaceRecord = requireWorkspace(session, input.sessionId);
634→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
635→  const diffResult = await input.getDiff(repoRoot, branchName);
636→
637→  const diff = diffResult.ok
638→    ? diffResult.value
639→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
640→
641→  // Get task title
642→  const taskId = session.task_id ? session.task_id.id : "";
643→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
644→
645→  return {
646→    ok: true,
647→    value: {
648→      taskTitle,
649→      diff,
650→      session: {
651→        orchestratorStatus: status,
652→        ...pickDefined({
653→          worktreeBranch: session.worktree_branch,
654→          startedAt: session.started_at,
655→          lastEventAt: session.last_event_at,
656→        }),
657→      },
658→    },
659→  };
660→}
